import {EventEmitter} from 'events';
import jibo = require('jibo');
import {Locality} from 'jibo-radio';

const OUR_RULE = 'radio/run_control';

export default class LocalGlobal extends EventEmitter {

    // event when user gives HJ command to show volume
    VOLUME: string = 'volumeQuery';
    // event when user gives HJ command to dance
    DANCE: string = 'startDancing';
    // event when user gives HJ command to stop dancing
    STOP_DANCING: string = 'stopDancing';
    STATIONS: string = 'stations';
    // event when user gives HJ command to say which genre is playing
    CURRENT_GENRE: string = 'currentGenre';
    // event when user gives HJ command to say which track is playing
    CURRENT_TRACK: string = 'currentTrack';
    LOCAL: string = Locality.Local;
    NATIONAL: string = Locality.National;

    // We need a rule. It has a flexible format:
    // Must be syntactically valid .rule file content,
    // OR path to .fst file,
    // OR a rule handle.
    private _listener: jibo.jetstream.HotwordModeToken;
    private _nowListening: boolean = false;
    private _shouldRelisten: boolean = true;

    constructor(assetPack: string) {
        super();
    }

    get persistent(): boolean {
        return this._shouldRelisten;
    }
    set persistent(flag: boolean) {
        this._shouldRelisten = flag;
    }

    init(): Promise<void> {
        return Promise.resolve();
    }

    startListening() {
        if (!this._nowListening) {
            jibo.globalEvents.shared.hjOnly.on(this._cloudHandler as any);
            //TODO: actual rule content somehow
            this._listener = jibo.jetstream.setHotwordMode(jibo.jetstream.types.HotwordListenMode.Custom_NLU_Added, [OUR_RULE]);
            this._listener.match.on(this._cloudHandler);
            this._nowListening = true;
        }
    }

    stopListening() {
        this._destroyListener();
    }

    destroy() {
        this._shouldRelisten = false;
        this.removeAllListeners();
        this.stopListening();
    }

    private _cloudHandler = (data): void => {
        const eventName = this._parseListenResults(data);
        if (eventName) {
            this.emit(eventName, eventName);
            jibo.globalEvents.shared.nonInterruptingGlobal.emit();
        }
        this._destroyListener();
        if (this.persistent) {
            this.startListening();
        }
    }

    private _destroyListener(): void {
        jibo.globalEvents.shared.hjOnly.off(this._cloudHandler as any);
        if (this._listener) {
            this._listener.match.off(this._cloudHandler);
            this._listener.release();
            this._listener = null;
        }
        this._nowListening = false;
    }

    private _parseListenResults(data:jibo.jetstream.types.SuccessTurnResult): string {
        let eventName = '';
        if (!data || !data.result || !data.result.nlu) {
            return eventName;
        }
        switch (data.result.nlu.intent) {
            case 'start_dancing':
                eventName = this.DANCE;
                break;
            case 'stop_dancing':
                eventName = this.STOP_DANCING;
                break;
            case 'get_volume':
                eventName = this.VOLUME;
                break;
            case 'stations':
                eventName = this.STATIONS;
                break;
            case 'get_genre':
                eventName = this.CURRENT_GENRE;
                break;
            case 'get_track':
                eventName = this.CURRENT_TRACK;
                break;
            case 'local':
                eventName = this.LOCAL;
                break;
            case 'national':
                eventName = this.NATIONAL;
                break;
            default:
                break;
        }
        return eventName;
    }
}
